from functools import lru_cache
from itertools import combinations

class Solution:
    def maxCoins(self, piles):
        state = tuple(sorted(piles))

        @lru_cache(maxsize=None)
        def rec(remaining):
            if not remaining:
                return 0
            m = len(remaining)
            best = 0
            for combo in combinations(range(m), 3):
                chosen = sorted(remaining[i] for i in combo)
                you_get = chosen[1]
                rest = tuple(remaining[i] for i in range(m) if i not in combo)
                cand = you_get + rec(rest)
                if cand > best:
                    best = cand
            return best

        result = rec(state)
        rec.cache_clear()
        return result

