var maxCoins = function(piles) {
    const sorted = piles.slice().sort((a, b) => a - b);
    const n = Math.floor(sorted.length / 3);
    let total = 0;
    for (let i = n; i < sorted.length - 1; i += 2) total += sorted[i];
    return total;
};
